Def:
=Floor(If('$(vOpsScorecardActor)'='Processor',

		Avg(
        	{1<[$(vOpsScorecardActor)_Production] *= {$(vCurrentProduction)},
            [Sent To Underwriting Previous QTD] = {Yes},
            [$(vOpsScorecardActor)] -= {'99-Missing'}>}
            [Sent To Underwriting]-[Sent To Processing]
        ),

    If('$(vOpsScorecardActor)'='Underwriter',

    	Avg(
        {1<[$(vOpsScorecardActor)_Production] *= {$(vCurrentProduction)},
        [Sent To Closing Previous QTD] = {Yes},
        [$(vOpsScorecardActor)] -= {'99-Missing'}>}
        [Sent To Closing]-[Sent To Underwriting]
        ),

	If('$(vOpsScorecardActor)'='Closer',

    	Avg(
        	{1<[$(vOpsScorecardActor)_Production] *= {$(vCurrentProduction)},
            [End Date Previous QTD] = {Yes},
            [$(vOpsScorecardActor)] -= {'99-Missing'}>}
            [End Date]-[Sent To Closing]
        )
	)
    )
    )
)

