    	Count({<DateType*={'Application'}, [Date] *= {">=$(=Date(vCurrentDateAsDate-vShotTermPullThroughRange))<=$(=Date(vCurrentDateAsDate))"}, [Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}, [Channel Group]*={'$(vChannelGroup)'}, $(vScorecardMissingLevel),$(vScorecardIgnoreLevel)>}[Loan Number])
