Avg({$<[CCA Scorecard Margin $] *= {"0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr({$<[CCA Scorecard Margin $] *= {"0"},$(vCCA_ScorecardIgnoreLevel)>}
    	[CCA Scorecard Margin $]
        ,$(vCCA_ScorecardAggrLevel))) = 0,100,

Avg({$<[CCA Scorecard Margin $] *= {"0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr({$<[CCA Scorecard Margin $] *= {"0"},$(vCCA_ScorecardIgnoreLevel)>}
    	[CCA Scorecard Margin $]
        ,$(vCCA_ScorecardAggrLevel)))
)

DefExpanded:
=If(
Avg({$<[CCA Scorecard Margin $] *= {"0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[CCA Scorecard Margin $] *= {"0"},[Loan Officer]*=>}
    	[CCA Scorecard Margin $]
        ,[Loan Officer])) = 0,100,

Avg({$<[CCA Scorecard Margin $] *= {"0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[CCA Scorecard Margin $] *= {"0"},[Loan Officer]*=>}
    	[CCA Scorecard Margin $]
        ,[Loan Officer]))
)

Def:
=If(
Avg({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"},$(vCCA_ScorecardIgnoreLevel)>}
    	[CCA Scorecard Margin $_ShortTerm]
        ,$(vCCA_ScorecardAggrLevel))) = 0,100,

Avg({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"},$(vCCA_ScorecardIgnoreLevel)>}
    	[CCA Scorecard Margin $_ShortTerm]
        ,$(vCCA_ScorecardAggrLevel)))
)

DefExpanded:
=If(
Avg({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"},[Loan Officer]*=>}
    	[CCA Scorecard Margin $_ShortTerm]
        ,[Loan Officer])) = 0,100,

Avg({$<[CCA Scorecard Margin $_ShortTerm] *= {"0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
