        ,[Loan Officer]))

=Avg({$<[CCA Scorecard PullThrough_ShortTerm] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[Loan Officer]*=>}
    	[CCA Scorecard PullThrough_ShortTerm]
        ,[Loan Officer]
    )
)

Def:
=Avg({$<[CCA Scorecard TurnTime] *= {">0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr(
    {$<[CCA Scorecard TurnTime] *= {">0"},$(vCCA_ScorecardIgnoreLevel)>}
    	Pow([CCA Scorecard TurnTime]
        ,-1),$(vCCA_ScorecardAggrLevel)))

DefExpanded:
=Avg({$<[CCA Scorecard TurnTime] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr(
    {$<[CCA Scorecard TurnTime] *= {">0"},[Loan Officer]*=>}
    	Pow([CCA Scorecard TurnTime]
        ,-1),[Loan Officer]))

Def:
=Avg({$<[CCA Scorecard TurnTime_ShortTerm] *= {">0"}, $(vCCA_ScorecardMissingLevel),$(vCCA_ScorecardIgnoreLevel)>}
	Aggr(
    {$<[CCA Scorecard TurnTime_ShortTerm] *= {">0"},$(vCCA_ScorecardIgnoreLevel)>}
    	Pow([CCA Scorecard TurnTime_ShortTerm]
        ,-1),$(vCCA_ScorecardAggrLevel)))

DefExpanded:
=Avg({$<[CCA Scorecard TurnTime_ShortTerm] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr(
    {$<[CCA Scorecard TurnTime_ShortTerm] *= {">0"},[Loan Officer]*=>}
    	Pow([CCA Scorecard TurnTime_ShortTerm]
        ,-1),[Loan Officer]))

=Avg({$<[CCA Scorecard Volume] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[Loan Officer]*=>}
    	[CCA Scorecard Volume]
        ,[Loan Officer]))

=Avg({$<[CCA Scorecard Volume_ShortTerm] *= {">0"}, [Loan Officer Missing]*={0},[Loan Officer]*=>}
	Aggr({$<[Loan Officer]*=>}
    	[CCA Scorecard Volume_ShortTerm]
        ,[Loan Officer]))

if (
   '' = 'Loan Program',
    [TVI Loan Program Score_4Months],
   ( (
num ( ([CCA Scorecard Volume_ShortTerm]/3173010.4)*100  , '' )*2
// ([TVI Volume Rating_2Months]*$(vScorecardVolumeWeight)
+
num ( ([CCA Scorecard Margin $_ShortTerm]/89504.555405405)*100     , '' )*2
// [TVI Margin Rating_2Months]*$(vScorecardMarginWeight)
+
num ( (  Pow ( [CCA Scorecard TurnTime_ShortTerm], -1 ) / 0.029661938 *100)    , '' )  /* *( $(eCCA_TVI_VolumeRating_ShortTerm) /100)*/ *0.5
// [TVI Turn Times Rating_2Months]*([TVI Volume Rating_2Months]/100)*$(vScorecardTurnTimeWeight)
+
num ( ([CCA Scorecard PullThrough_ShortTerm]/0.6998961)*100    , '' ) /* * ( $(eCCA_TVI_MarginRating_ShortTerm)  /100)*/ *1.5
// [TVI Pull Through Rating_2Months]*([TVI Margin Rating_2Months]/100)*$(vScorecardPullThroughWeight)
+
num (  ([CCA Scorecard Unit_ShortTerm]/13.081081)*100   , '' ) * 2
+
Pick(vCCA_ScorecardIncludeConcession_ShortTerm, 0,num (  ([CCA Scorecard Concession_ShortTerm]/0)*100   , '' )) * 2
)
/
(2+2+0.5+1.5+2+Pick(vCCA_ScorecardIncludeConcession_ShortTerm, 0,2)) )
)

Def:
aggr ( 
	if ( 
		$(eCCA_TVI_Score_13_Months) >= 120, 
	    Dual ('Top Tier', 1), 
        if (
	    	$(eCCA_TVI_Score_13_Months) >= 80, 
		      Dual ('Second Tier', 2), 
			if ( 
            	$(eCCA_TVI_Score_13_Months) >= 0, 		     
		        Dual ( 'Bottom Tier' , 3 ),
                null()
	    )
       ) 
	),
    [$(vCCA_ParetoDim)]
)

aggr ( 
	if ( 
		$(eCCA_TVI_Score_13_Months) >= 120, 
	    Dual ('Top Tier', 1), 
        if (
	    	$(eCCA_TVI_Score_13_Months) >= 80, 
		      Dual ('Second Tier', 2), 
			if ( 
            	$(eCCA_TVI_Score_13_Months) >= 0, 		     
		        Dual ( 'Bottom Tier' , 3 ),
//                Dual ( 'Undefined', 4)
                null()
	    )
       ) 
	),
    [$(vCCA_ParetoDim)]
)

