Def:
Pick(
    Match(
        ScorecardActors, 
        'Processors', 'Processor Units', 'Processor Volume', 'Processor Turn Times', 'Processor Min TVI', 'Processor Max TVI',
        'Underwriters', 'Underwriter Units', 'Underwriter Volume', 'Underwriter Avg Conditions', 'Underwriter % Approved', 'Underwriter % Denied',
        'Underwriter Turn Times', 'Underwriter Min TVI', 'Underwriter Max TVI', 
        'Closers', 'Closer Units', 'Closer Volume', 'Closer Turn Times', 'Closer Min TVI', 'Closer Max TVI'
    ),

    Num(
        Count({
            <
                [Processor_Production] *= {$(vCurrentProduction)},
                Processor *= {'$(=[Processors Top Tier])'},
                [Processor Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Processor Missing] *= {0}
            >
        } distinct [Processor]), 
        '#,##0'
    ),

    Num(
        Count({
            <
                [Processor_Production] *= {$(vCurrentProduction)},
                Processor *= {'$(=[Processors Top Tier])'},
                [Processor Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Processor Missing] *= {0}
            >
        } distinct [Loan Number]), 
        '#,##0'
    ),

    Num(
        Sum({
            <
                [Processor_Production] *= {$(vCurrentProduction)},
                Processor *= {'$(=[Processors Top Tier])'},
                [Processor Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Processor Missing] *= {0}
            >
        } [Loan Amount]), 
        '$#,##0'
    ),

    $(=$(vProcessorTopTT)),

    Num($(=$(vTopProcMin)), '#,##0.00'),
    Num($(=$(vTopProcMax)), '#,##0.00'),

    Num(
        Count({
            <
                [Underwriter_Production] *= {$(vCurrentProduction)},
                Underwriter *= {'$(=[Underwriters Top Tier])'},
                [Underwriter Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Underwriter Missing] *= {0}
            >
        } distinct [Underwriter]),
        '#,##0'
    ),

    Num(
        Count({
            <
                [Underwriter_Production] *= {$(vCurrentProduction)},
                Underwriter *= {'$(=[Underwriters Top Tier])'},
                [Underwriter Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Underwriter Missing] *= {0}
            >
        } distinct [Loan Number]), 
        '#,##0'
    ),

    Num(
        Sum({
            <
                [Underwriter_Production] *= {$(vCurrentProduction)},
                Underwriter *= {'$(=[Underwriters Top Tier])'},
                [Underwriter Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Underwriter Missing] *= {0}
            >
        } [Loan Amount]), 
        '$#,##0'
    ),

    $(=$(vUnderwriterTopConditions)),
    '$(=$(vUnderwriterTopApproved))',
    '$(=$(vUnderwriterTopDenied))',
    $(=$(vUnderwriterTopTT)),

    Num($(=$(vTopUWMin)), '#,##0.00'),
    Num($(=$(vTopUWMax)), '#,##0.00'),

    Num(
        Count({
            <
                [Closer_Production] *= {$(vCurrentProduction)},
                Closer *= {'$(=[Closers Top Tier])'},
                [Closer Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Closer Missing] *= {0}
            >
        } distinct [Closer]), 
        '#,##0'
    ),

    Num(
        Count({
            <
                [Closer_Production] *= {$(vCurrentProduction)},
                Closer *= {'$(=[Closers Top Tier])'},
                [Closer Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Closer Missing] *= {0}
            >
        } distinct [Loan Number]), 
        '#,##0'
    ),

    Num(
        Sum({
            <
                [Closer_Production] *= {$(vCurrentProduction)},
                Closer *= {'$(=[Closers Top Tier])'},
                [Closer Interval] *= {"Last $(vOpsScorecardMonthRange) Months"},
                [Closer Missing] *= {0}
            >
        } [Loan Amount]), 
        '$#,##0'
    ),

    $(=$(vCloserTopTT)),

    Num($(=$(vTopCloserMin)), '#,##0.00'),
    Num($(=$(vTopCloserMax)), '#,##0.00')
)

