Def:
num (

If('$(vCurrentProduction)' = 'Yes',

if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))=0,0,
Sum({<[Loan Number]={$(vClosingProjectionLoanList)},[Current Loan Status Group]=,[Current Loan Status]=>}[Loan Amount])


)

,
If('$(vCurrentProduction)' = 'No',
if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))>0,0,
Sum({<[Loan Number]={$(vClosingProjectionLoanList)},[Current Loan Status Group]=,[Current Loan Status]=>}[Loan Amount])

)

,

if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))<0,0,
Sum({<[Loan Number]={$(vClosingProjectionLoanList)},[Current Loan Status Group]=,[Current Loan Status]=>}[Loan Amount])


)
)),
'#,##0'
)

If('$(vCurrentProduction)' = 'Yes',
if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))=0,0,
Count({<[Loan Number]={$(vClosingProjectionLoanList)},[Current Loan Status Group]=,[Current Loan Status]=>}[Loan Number])
)
,
If('$(vCurrentProduction)' = 'No',
if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))>0,0,
Count({<[Loan Number]={$(vClosingProjectionLoanList)},[Current Loan Status Group]=,[Current Loan Status]=>}[Loan Number])
)
,
if(Sum(Aggr([Current Production Check],$(vScorecardAggrLevel)))<0,0,
